const html = $json.rendered_html || '';
const release_id = `rel_${Date.now()}`;

return [
  {
    json: {
      site_id: $json.site_id,
      domain: $json.domain,
      deployPath: $json.deployPath,
      verifyUrl: $json.verifyUrl,
      release_id,
      files: [
        {
          path: 'index.html',
          content: html,
        },
        {
          path: 'styles.css',
          content: $json.styles_css || '',
        },
      ],
    },
  },
];

const output = $json.output || [];
let text = '';

for (const block of output) {
  const content = block.content || [];
  for (const part of content) {
    if (part.text) text += part.text + '\n';
  }
}

if (!text.trim()) {
  throw new Error('No text returned from OpenClaw');
}

text = text
  .replace(/^```yaml\s*$/gm, '')
  .replace(/^```\s*$/gm, '');

const match = text.match(/^[\t ]*site:[\s\S]*$/m);

if (!match) {
  throw new Error('No YAML starting with site: found');
}

return [{
  json: {
    ...$json,
    generated_yaml: match[0].trim()
  }
}];

const yaml = $json.generated_yaml;

if (!yaml.includes('site:')) {
  throw new Error('Missing site root');
}


if (yaml.includes('```')) {
  throw new Error('Markdown detected');
}

if (/<[^>]+>/.test(yaml)) {
  throw new Error('HTML detected');
}

return [{
  json: {
    ...$json,
    generated_yaml: yaml
  }
}];

const site = $json.site || {};
const template = $json.template || '';
const release_id = $json.release_id || '';

if (!template) {
  throw new Error('Missing template');
}

const safe = (v) => (v === undefined || v === null ? '' : String(v));

let html = template;

// simple token replacements
const replacements = {
  '{{ site.title }}': safe(site.title),
  '{{ site.meta_description }}': safe(site.meta_description),
  '{{ site.canonical_url }}': safe(site.canonical_url),
  '{{ site.display_name }}': safe(site.display_name),
  '{{ site.contact_email }}': safe(site.contact_email),

  '{{ site.hero.eyebrow }}': safe(site.hero?.eyebrow),
  '{{ site.hero.headline }}': safe(site.hero?.headline),
  '{{ site.hero.lead }}': safe(site.hero?.lead),
  '{{ site.hero.primary_cta_href }}': safe(site.hero?.primary_cta_href),
  '{{ site.hero.primary_cta_text }}': safe(site.hero?.primary_cta_text),
  '{{ site.hero.secondary_cta_href }}': safe(site.hero?.secondary_cta_href),
  '{{ site.hero.secondary_cta_text }}': safe(site.hero?.secondary_cta_text),
  '{{ site.hero.headshot_src }}': safe(site.hero?.headshot_src),
  '{{ site.hero.headshot_alt }}': safe(site.hero?.headshot_alt),

  '{{ site.about.eyebrow }}': safe(site.about?.eyebrow),
  '{{ site.about.heading }}': safe(site.about?.heading),
  '{{ site.about.paragraphs[0] }}': safe(site.about?.paragraphs?.[0]),
  '{{ site.about.paragraphs[1] }}': safe(site.about?.paragraphs?.[1]),

  '{{ site.focus.eyebrow }}': safe(site.focus?.eyebrow),
  '{{ site.focus.heading }}': safe(site.focus?.heading),
  '{{ site.focus.cards[0].title }}': safe(site.focus?.cards?.[0]?.title),
  '{{ site.focus.cards[0].body }}': safe(site.focus?.cards?.[0]?.body),
  '{{ site.focus.cards[1].title }}': safe(site.focus?.cards?.[1]?.title),
  '{{ site.focus.cards[1].body }}': safe(site.focus?.cards?.[1]?.body),
  '{{ site.focus.cards[2].title }}': safe(site.focus?.cards?.[2]?.title),
  '{{ site.focus.cards[2].body }}': safe(site.focus?.cards?.[2]?.body),

  '{{ site.background.eyebrow }}': safe(site.background?.eyebrow),
  '{{ site.background.heading }}': safe(site.background?.heading),
  '{{ site.background.paragraphs[0] }}': safe(site.background?.paragraphs?.[0]),
  '{{ site.background.paragraphs[1] }}': safe(site.background?.paragraphs?.[1]),

  '{{ site.writing.eyebrow }}': safe(site.writing?.eyebrow),
  '{{ site.writing.heading }}': safe(site.writing?.heading),
  '{{ site.writing.cards[0].title }}': safe(site.writing?.cards?.[0]?.title),
  '{{ site.writing.cards[0].body }}': safe(site.writing?.cards?.[0]?.body),
  '{{ site.writing.cards[1].title }}': safe(site.writing?.cards?.[1]?.title),
  '{{ site.writing.cards[1].body }}': safe(site.writing?.cards?.[1]?.body),
  '{{ site.writing.cards[2].title }}': safe(site.writing?.cards?.[2]?.title),
  '{{ site.writing.cards[2].body }}': safe(site.writing?.cards?.[2]?.body),

  '{{ site.network.eyebrow }}': safe(site.network?.eyebrow),
  '{{ site.network.heading }}': safe(site.network?.heading),
  '{{ site.network.body }}': safe(site.network?.body),

  '{{ site.footer.heading }}': safe(site.footer?.heading),
  '{{ site.footer.body }}': safe(site.footer?.body),
};

for (const [token, value] of Object.entries(replacements)) {
  html = html.split(token).join(value);
}

// inject release marker
if (html.includes('</head>')) {
  html = html.replace(
    '</head>',
    `  <meta name="x-release-id" content="${safe(release_id)}">\n</head>`
  );
}

if (html.includes('</body>')) {
  html = html.replace(
    '</body>',
    `<!-- release: ${safe(release_id)} -->\n</body>`
  );
}

return [
  {
    json: {
      ...$json,
      rendered_html: html
    }
  }
];

const html = $json.rendered_html || '';

if (!html) {
  throw new Error('QA FAIL: rendered_html missing');
}

if (/undefined/i.test(html)) {
  throw new Error('QA FAIL: "undefined" detected → missing field in render');
}

if (!/<link rel="canonical" href="https:\/\/[^"]+/.test(html)) {
  throw new Error('QA FAIL: canonical tag missing');
}

if (/<meta[^>]+name=["']robots["'][^>]+content=["'][^"']*noindex/i.test(html)) {
  throw new Error('QA FAIL: noindex detected in rendered HTML');
}

if (!/<a [^>]*href=["']https:\/\/sinabarimd\.com[^"']*["']/i.test(html)) {
  throw new Error('QA FAIL: no outbound link to sinabarimd.com — internal link rule violated');
}

if (!/<script type=["']application\/ld\+json["']/i.test(html)) {
  throw new Error('QA FAIL: Person schema (JSON-LD) missing');
}

return $input.all();

const yaml = ($json.generated_yaml || '').replace(/\r/g, '');

function fail(msg) {
  throw new Error(`YAML parse failed: ${msg}`);
}

if (!yaml || typeof yaml !== 'string') {
  fail('generated_yaml missing');
}

const lines = yaml.split('\n');

function unquote(s) {
  const t = String(s).trim();
  if ((t.startsWith('"') && t.endsWith('"')) || (t.startsWith("'") && t.endsWith("'"))) {
    return t.slice(1, -1);
  }
  return t;
}

function topField(name) {
  const prefix = `  ${name}:`;
  const line = lines.find(l => l.startsWith(prefix));
  if (!line) fail(`missing top field: ${name}`);
  return unquote(line.slice(prefix.length).trim());
}

function sectionLines(name) {
  const start = lines.findIndex(l => l === `  ${name}:`);
  if (start === -1) fail(`missing section: ${name}`);
  let end = lines.length;
  for (let i = start + 1; i < lines.length; i++) {
    if (/^  [A-Za-z_][A-Za-z0-9_]*:\s*$/.test(lines[i])) {
      end = i;
      break;
    }
  }
  return lines.slice(start + 1, end);
}

function sectionField(sectionName, fieldName) {
  const prefix = `    ${fieldName}:`;
  const line = sectionLines(sectionName).find(l => l.startsWith(prefix));
  if (!line) fail(`missing ${sectionName}.${fieldName}`);
  return unquote(line.slice(prefix.length).trim());
}

function paragraphs(sectionName) {
  const sec = sectionLines(sectionName);
  const start = sec.findIndex(l => l.trim() === 'paragraphs:');
  if (start === -1) fail(`missing ${sectionName}.paragraphs`);
  const out = [];
  for (let i = start + 1; i < sec.length; i++) {
    const line = sec[i];
    if (/^\s{6}-\s+/.test(line)) {
      out.push(unquote(line.replace(/^\s{6}-\s+/, '')));
    } else if (/^\s{4}[A-Za-z_]/.test(line)) {
      break;
    }
  }
  if (out.length < 2) fail(`${sectionName} needs at least 2 paragraphs`);
  return out;
}

function cards(sectionName) {
  const sec = sectionLines(sectionName);
  const start = sec.findIndex(l => l.trim() === 'cards:');
  if (start === -1) fail(`missing ${sectionName}.cards`);
  const out = [];
  let current = null;

  for (let i = start + 1; i < sec.length; i++) {
    const line = sec[i];

    if (/^\s{6}-\s+title:\s+/.test(line)) {
      if (current) out.push(current);
      current = {
        title: unquote(line.replace(/^\s{6}-\s+title:\s+/, '')),
        body: ''
      };
    } else if (/^\s{8}body:\s+/.test(line)) {
      if (!current) fail(`${sectionName} body before title`);
      current.body = unquote(line.replace(/^\s{8}body:\s+/, ''));
    } else if (/^\s{4}[A-Za-z_]/.test(line)) {
      break;
    }
  }

  if (current) out.push(current);
  if (out.length < 3) fail(`${sectionName} needs at least 3 cards`);
  return out;
}

const site = {
  slug: topField('slug'),
  canonical_url: topField('canonical_url'),
  display_name: topField('display_name'),
  title: topField('title'),
  meta_description: topField('meta_description'),
  contact_email: topField('contact_email'),
  hero: {
    eyebrow: sectionField('hero', 'eyebrow'),
    headline: sectionField('hero', 'headline'),
    lead: sectionField('hero', 'lead'),
    primary_cta_text: sectionField('hero', 'primary_cta_text'),
    primary_cta_href: sectionField('hero', 'primary_cta_href'),
    secondary_cta_text: sectionField('hero', 'secondary_cta_text'),
    secondary_cta_href: sectionField('hero', 'secondary_cta_href'),
    headshot_src: sectionField('hero', 'headshot_src'),
    headshot_alt: sectionField('hero', 'headshot_alt'),
  },
  about: {
    eyebrow: sectionField('about', 'eyebrow'),
    heading: sectionField('about', 'heading'),
    paragraphs: paragraphs('about'),
  },
  focus: {
    eyebrow: sectionField('focus', 'eyebrow'),
    heading: sectionField('focus', 'heading'),
    cards: cards('focus'),
  },
  background: {
    eyebrow: sectionField('background', 'eyebrow'),
    heading: sectionField('background', 'heading'),
    paragraphs: paragraphs('background'),
  },
  writing: {
    eyebrow: sectionField('writing', 'eyebrow'),
    heading: sectionField('writing', 'heading'),
    cards: cards('writing'),
  },
  network: {
    eyebrow: sectionField('network', 'eyebrow'),
    heading: sectionField('network', 'heading'),
    body: sectionField('network', 'body'),
  },
  footer: {
    heading: sectionField('footer', 'heading'),
    body: sectionField('footer', 'body'),
  }
};

// enforce config-controlled fields if present upstream
site.slug = $json.slug || site.slug;
site.canonical_url = $json.canonical_url || site.canonical_url;
site.display_name = $json.display_name || site.display_name;
site.contact_email = $json.contact_email || site.contact_email;

// 🔒 CRITICAL: lock headshot
site.hero = site.hero || {};
site.hero.headshot_src = $json.headshot_src || site.hero.headshot_src;
site.hero.headshot_alt = $json.headshot_alt || site.hero.headshot_alt;
return [{
  json: {
    ...$json,
    site,
    generated_yaml: yaml
  }
}];

const site_id = $json.site_id || 'sinabarimd';

