:root{
  --ink:#111318;--muted:#525866;--accent:#0f3f6e;--border:#dde0da;
  --bg:#fafaf8;--card:#ffffff;--max:1100px;
  --shadow:0 8px 32px rgba(15,30,60,.07);--r:18px;
}
html{scroll-behavior:smooth}
body{font-family:Inter,ui-sans-serif,system-ui,sans-serif;background:var(--bg);color:var(--ink);line-height:1.65}
a{color:var(--accent);text-decoration:none}
