.nav-wrap{display:flex;align-items:center;justify-content:space-between;min-height:68px;gap:1rem}
.wordmark{font-weight:700;font-size:1.05rem;color:var(--ink);letter-spacing:-.02em}
nav{display:flex;gap:1.5rem}
nav a{color:var(--muted);font-size:.9rem;font-weight:500}

/* HERO */
.hero{padding:7rem 0 5rem}
.hero-wrap{display:grid;grid-template-columns:1.4fr .6fr;gap:2.5rem;align-items:center}
.label{font-size:.72rem;font-weight:700;letter-spacing:.14em;text-transform:uppercase;
  color:var(--accent);margin-bottom:.9rem}
h1{font-size:clamp(2.8rem,5.5vw,4.8rem);letter-spacing:-.04em;line-height:1.05;
  margin-bottom:1.1rem;font-weight:800}
h2{font-size:clamp(1.7rem,2.8vw,2.5rem);letter-spacing:-.03em;line-height:1.1;margin-bottom:.8rem}
h3{font-size:1.05rem;letter-spacing:-.01em;margin-bottom:.45rem;font-weight:700}
.lead{font-size:1.12rem;color:var(--muted);max-width:40rem;line-height:1.7}
.hero-actions{display:flex;gap:1rem;flex-wrap:wrap;margin-top:2.2rem}
.btn-primary,.btn-ghost{
  display:inline-flex;align-items:center;min-height:46px;padding:.7rem 1.4rem;
  border-radius:999px;font-weight:600;font-size:.95rem;transition:opacity .15s}
.btn-primary{background:var(--accent);color:#fff;box-shadow:var(--shadow)}
.btn-ghost{background:var(--card);color:var(--ink);border:1px solid var(--border);box-shadow:var(--shadow)}
.btn-primary:hover,.btn-ghost:hover{opacity:.85;text-decoration:none}
.hero-portrait img{width:100%;max-height:420px;object-fit:cover;object-position:top;border-radius:var(--r);box-shadow:var(--shadow);display:block}

/* SECTIONS */
.section{padding:5rem 0}
.section-tinted{background:rgba(235,236,230,.5);border-top:1px solid var(--border);border-bottom:1px solid var(--border)}
.prose-cols{display:grid;grid-template-columns:1fr 1fr;gap:2rem;margin-top:1.5rem}
.prose-cols p{color:var(--muted);line-height:1.75}

/* FEATURE GRID */
.feature-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:1.25rem;margin-top:1.75rem}
.feature-card{background:var(--card);border:1px solid var(--border);border-radius:var(--r);
  padding:1.6rem;box-shadow:var(--shadow)}
.feature-card p{color:var(--muted);margin-top:.4rem;font-size:.95rem;line-height:1.7}

/* WRITING LIST */
